const body = $json.body || $json;
const message = body.message || '';
const projectId = body.project_id || ('proj-' + Date.now());
return [{ json: { message, project_id: projectId, operation: 'init', goal: message } }];

const memory = $json;
const message = $('Extract Input').first().json.message;
return [{ json: {
  message: message,
  project_goal: memory.goal || message,
  project_id: memory.project_id
} }];

const tasks = $json.tasks || [];
const plannerInput = $('Prepare Planner Input').first().json;
const projectId = plannerInput.project_id;
const projectGoal = plannerInput.project_goal;
if (tasks.length === 0) {
  return [{ json: { task: { task_id: 'T1', description: 'No tasks planned' }, project_id: projectId, project_goal: projectGoal } }];
}
return tasks.map(task => ({ json: { task, project_id: projectId, project_goal: projectGoal } }));

const taskResults = $input.all().map(item => item.json);
const allFiles = [...new Set(taskResults.flatMap(r => r.files_written || []))];
const projectId = $('Prepare Planner Input').first().json.project_id;
const projectGoal = $('Prepare Planner Input').first().json.project_goal;
return [{ json: { task_results: taskResults, all_files: allFiles, project_id: projectId, project_goal: projectGoal } }];

const taskResults = $json.task_results || [];
const allFiles = $json.all_files || [];
const projectId = $json.project_id;
const completedTaskIds = taskResults.map(r => r.task_id);
return [{ json: {
  operation: 'set',
  project_id: projectId,
  state: {
    status: 'active',
    completed_tasks: completedTaskIds,
    files: allFiles
  }
} }];

const memory = $json;
const aggregated = $('Aggregate All Results').first().json;
return [{ json: {
  status: 'completed',
  project_id: memory.project_id,
  project_goal: memory.goal,
  tasks_completed: (aggregated.task_results || []).length,
  task_results: aggregated.task_results || [],
  files_written: memory.files || []
} }];
